// Define a function to parse the media query string and return the parsed object
function parseMediaQuery(query) {
    let features = query.split(' and ');
    let parsedFeatures = [];
    for (let feature of features) {
        let [name, value] = feature.split(':');
        parsedFeatures.push({name, value});
    }
    return parsedFeatures;
}

